"Reason For Not Administering Antithrombotic" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('id', fhirpath_text(MedicationAdm.resource, 'id'), 'authoredOn', fhirpath_text(MedicationAdm.resource, 'extension.where(url=''http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-recorded'').valueDateTime')) AS _resource_data FROM "MedicationAdministration: Antithrombotic Therapy for Ischemic Stroke (medicationadministrationnotdone)" AS MedicationAdm WHERE in_valueset(MedicationAdm.resource, 'statusReason', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.473') OR in_valueset(MedicationAdm.resource, 'statusReason', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.93')) AS _inner
),
"Reason For Not Ordering Antithrombotic" AS (
(SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('id', fhirpath_text(NoAntithromboticOrder.resource, 'id'), 'authoredOn', NoAntithromboticOrder.authored_date) AS _resource_data FROM "MedicationRequest: Antithrombotic Therapy for Ischemic Stroke (medicationnotrequested)" AS NoAntithromboticOrder WHERE (in_valueset(NoAntithromboticOrder.resource, 'reasonCode', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.473') OR in_valueset(NoAntithromboticOrder.resource, 'reasonCode', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.93')) AND array_contains(['active', 'completed'], NoAntithromboticOrder.status) AND array_contains(['order', 'original-order', 'reflex-order', 'filler-order', 'instance-order'], NoAntithromboticOrder.intent)) AS _inner) UNION (SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('id', fhirpath_text(MedReqAntithrombotic.resource, 'id'), 'authoredOn', MedReqAntithrombotic.authored_date) AS _resource_data FROM "MedicationRequest: Antithrombotic Therapy for Ischemic Stroke" AS MedReqAntithrombotic WHERE EXISTS (SELECT 1 FROM "Task" AS TaskReject WHERE fhirpath_text(MedReqAntithrombotic.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(TaskReject.resource, 'focus.reference'), '/'), -1) AND (in_valueset(TaskReject.resource, 'statusReason', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.473') OR in_valueset(TaskReject.resource, 'statusReason', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.117.1.7.1.93')) AND array_contains(['active', 'completed'], fhirpath_text(MedReqAntithrombotic.resource, 'status')) AND fhirpath_bool(TaskReject.resource, 'code.coding.where(system=''http://hl7.org/fhir/CodeSystem/task-code'' and code=''fulfill'').exists()') AND TaskReject.patient_id = MedReqAntithrombotic.patient_id)) AS _inner)
),
